"""HLD Core Concepts: Networking Essentials, API Design, Data Modeling — 20 MCQs each."""
from __future__ import annotations
from .lld_practice import quiz, Lesson

def networking_lesson() -> Lesson:
    return Lesson(id="hld-networking", number=100, title="Networking Essentials",
        focus=("TCP/UDP","HTTP/2","DNS","WebSockets","CDN","load balancing"),
        overview="Networking fundamentals that underpin every system design.",
        patterns=(), badge="HLD Core", tasks=(
        quiz("net-1","What is the key difference between TCP and UDP?","medium",("networking",),("UDP provides ordered delivery with checksums; TCP does not guarantee ordering","TCP guarantees delivery and ordering; UDP does not","TCP is connectionless and faster; UDP maintains persistent connections","UDP uses three-way handshake; TCP sends datagrams without acknowledgment"),1,"TCP provides reliable, ordered delivery via handshakes. UDP sacrifices that for lower latency."),
        quiz("net-2","Why would you choose UDP over TCP for live video streaming?","medium",("networking",),("UDP supports built-in congestion control for media streams","TCP's retransmission provides better video quality at scale","UDP handles larger payloads through frame segmentation","Lower latency — a few dropped frames beat head-of-line blocking"),3,"For real-time media, occasional packet loss is preferable to TCP's retransmission delays."),
        quiz("net-3","What does DNS resolve?","easy",("networking",),("Port numbers to running service instances on a host","IP addresses to physical MAC addresses on the LAN","Domain names to IP addresses","URL paths to file system locations on the server"),2,"DNS maps human-readable domain names to IP addresses."),
        quiz("net-4","What is the primary role of a load balancer?","easy",("networking",),("Cache API responses to reduce backend compute load","Distribute incoming traffic across multiple backend servers","Encrypt traffic between clients and origin servers","Manage DNS records and propagate zone updates"),1,"Load balancers prevent any single server from being overwhelmed."),
        quiz("net-5","What is the difference between L4 and L7 load balancing?","hard",("networking",),("L4 inspects HTTP request body for content-based routing decisions","L7 operates on raw TCP segments without parsing application data","L4 works at transport layer (TCP/UDP); L7 at application layer (HTTP)","L4 handles SSL termination; L7 only supports unencrypted traffic"),2,"L4 routes by IP/port; L7 makes decisions based on HTTP headers, paths, cookies."),
        quiz("net-6","When would you use WebSockets instead of HTTP polling?","medium",("networking",),("When you need strong caching of API responses at CDN edge","When server needs to push data to clients in real-time with low latency","When requests are infrequent and response payload is very large","When file uploads require chunked transfer encoding support"),1,"WebSockets maintain a persistent bidirectional connection for chat, live feeds, gaming."),
        quiz("net-7","What is Server-Sent Events (SSE) best suited for?","medium",("networking",),("Bidirectional real-time communication between client and server","Full-duplex binary streaming for inter-service gRPC calls","Database replication log shipping across data centers","Unidirectional server-to-client streaming over HTTP"),3,"SSE is simpler than WebSockets for one-way server push like live scores and notifications."),
        quiz("net-8","What is the purpose of a CDN?","easy",("networking",),("Replicate database state across multiple geographic regions","Serve static content from edge servers closer to users, reducing latency","Balance API traffic across backend application server pools","Provide end-to-end encryption between client and origin server"),1,"CDNs cache and serve static assets from edge locations, reducing latency."),
        quiz("net-9","What does a reverse proxy do?","medium",("networking",),("Sits in front of servers and forwards client requests to backends","Masks the client IP by routing through an intermediary exit node","Replaces DNS resolution with direct IP-based service routing","Encrypts database connections between application and storage tiers"),0,"A reverse proxy provides load balancing, SSL termination, and caching."),
        quiz("net-10","What is the thundering herd problem?","hard",("networking",),("Index fragmentation causing all queries to fall back to table scans","DNS propagation delay causing stale records across resolver caches","TCP timeout accumulation causing connection pool exhaustion","A surge of requests hitting a service simultaneously after a cache miss or restart"),3,"Mitigated with jitter, circuit breakers, or request coalescing."),
        quiz("net-11","What is gRPC and when would you prefer it over REST?","hard",("networking",),("A text-based protocol using JSON over HTTP/1.1 for browser clients","Uses Protocol Buffers over HTTP/2 for high-performance inter-service communication","A WebSocket replacement designed for persistent client connections","A streaming-only protocol that cannot handle unary request/response calls"),1,"gRPC offers binary serialization, multiplexing, and streaming — ideal for internal microservice calls."),
        quiz("net-12","What problem does connection pooling solve?","medium",("networking",),("SSL certificate rotation causing service interruptions during renewal","The overhead of repeatedly creating and destroying TCP connections","DNS latency from recursive resolution across nameserver hierarchies","Load balancer failover delays during health check interval gaps"),1,"Connection pools reuse connections, avoiding TCP handshake and TLS negotiation costs."),
        quiz("net-13","What is service discovery in microservices?","medium",("networking",),("A caching strategy that pre-warms data for newly deployed instances","A load balancing algorithm that routes by request content type","A mechanism for services to find each other's network locations dynamically","A debugging tool that traces requests across distributed service calls"),2,"Service discovery (Consul, K8s DNS) allows services to locate each other without hardcoded addresses."),
        quiz("net-14","What is the TCP three-way handshake?","medium",("networking",),("GET → POST → PUT sequence for RESTful resource lifecycle","SYN → SYN-ACK → ACK","CONNECT → ACCEPT → CLOSE for establishing proxy tunnels","REQUEST → RESPONSE → CONFIRM for idempotent message delivery"),1,"TCP connections begin with SYN from client, SYN-ACK from server, ACK from client."),
        quiz("net-15","Why is HTTP/2 preferred over HTTP/1.1?","hard",("networking",),("HTTP/2 uses XML-based framing for better compatibility with SOAP services","HTTP/2 eliminates the need for TLS, simplifying certificate management","Multiplexing multiple requests over a single connection, header compression, server push","HTTP/2 replaces TCP with UDP for lower latency on all request types"),2,"HTTP/2 eliminates head-of-line blocking at application layer with multiplexed streams."),
        quiz("net-16","What is a circuit breaker pattern?","hard",("networking",),("Stops calling a failing service after a threshold, preventing cascade failures","A physical hardware device that limits current flow to prevent overload","A database isolation level that prevents dirty reads between transactions","A load balancing technique that splits traffic between active and standby pools"),0,"Circuit breakers trip after N failures, returning errors immediately instead of waiting on a dead service."),
        quiz("net-17","What is the difference between horizontal and vertical scaling?","easy",("networking",),("Horizontal adds CPU/RAM to a single server; vertical adds more machines","Horizontal adds more machines; vertical upgrades existing machine resources","Vertical is always more cost-effective for stateless web applications","Horizontal requires shared-nothing architecture; vertical requires shared-everything"),1,"Horizontal (scale out) adds nodes; vertical (scale up) adds CPU/RAM to one node."),
        quiz("net-18","What is anycast routing?","hard",("networking",),("Routing to all servers simultaneously via broadcast for redundant processing","Routing to the nearest server sharing the same IP, used by CDNs and DNS","A multicast alternative that delivers packets to a subset of subscribers","A load balancing algorithm that round-robins across registered IP addresses"),1,"Anycast routes traffic to the topologically nearest node. Used by Cloudflare and DNS root servers."),
        quiz("net-19","What is HTTP long polling?","medium",("networking",),("Client sends repeated requests every fixed interval regardless of data availability","A WebSocket variant that falls back to HTTP when firewalls block upgrades","Server holds the request open until new data is available, then responds","A caching technique where the CDN polls the origin on behalf of the client"),2,"Long polling simulates server push: server delays response until new data, client re-requests immediately."),
        quiz("net-20","What is head-of-line blocking?","hard",("networking",),("When a slow/lost packet blocks all subsequent packets in the same connection","A DNS issue where stale cache entries block resolution of updated records","A CDN problem where edge cache misses cascade to overwhelm the origin","A firewall issue where deep packet inspection delays all traffic on a port"),0,"In HTTP/1.1, one slow request blocks all others on the same connection. HTTP/2 multiplexing solves this."),
    ))

def api_design_lesson() -> Lesson:
    return Lesson(id="hld-api-design", number=101, title="API Design",
        focus=("REST","GraphQL","idempotency","pagination","versioning","rate limiting"),
        overview="API design is critical in interviews — define endpoints, choose protocols, handle edge cases.",
        patterns=(), badge="HLD Core", tasks=(
        quiz("api-1","What makes an API call idempotent?","medium",("api",),("It always returns a cached response for identical parameters","The server processes it faster on subsequent retries","Making the same call multiple times produces the same result as once","It requires authentication before every invocation"),2,"Idempotency ensures retries are safe. PUT/DELETE are naturally idempotent; POST isn't."),
        quiz("api-2","Which HTTP methods are idempotent?","medium",("api",),("All HTTP methods are idempotent by specification","POST, PATCH, and OPTIONS are the idempotent methods","GET, PUT, DELETE","Only GET is idempotent; all write methods are non-idempotent"),2,"GET (safe), PUT, DELETE are idempotent. POST creates new resources each time."),
        quiz("api-3","When would you choose GraphQL over REST?","medium",("api",),("When the API only serves a single client with fixed data requirements","When you need simple file uploads with multipart form encoding","Clients need flexible queries and want to avoid over/under-fetching","When maximum simplicity and browser cacheability are the top priorities"),2,"GraphQL lets clients request exactly the fields they need."),
        quiz("api-4","What is the N+1 query problem?","hard",("api",),("Making N+1 separate API calls due to incorrect client-side batching","Fetching a list (1 query) then fetching related data for each item (N queries)","Having N+1 redundant HTTP methods on the same resource endpoint","Creating too many endpoints that each return overlapping data subsets"),1,"Solutions: batching, DataLoader pattern, or eager loading with JOINs."),
        quiz("api-5","What is an idempotency key?","hard",("api",),("An API version identifier embedded in the URL path for backward compatibility","A unique client-generated token to prevent duplicate processing on retries","A server-side session token that tracks authenticated user state","A database primary key used for optimistic locking on concurrent writes"),1,"Idempotency keys (e.g., Stripe's) let servers detect and deduplicate retried requests."),
        quiz("api-6","What is the difference between cursor-based and offset-based pagination?","hard",("api",),("They are functionally identical; cursor is just a renamed offset parameter","Cursor pagination is slower because it requires maintaining server-side state","Offset skips N rows (fragile with changes); cursor uses an opaque pointer (stable)","Offset is more accurate because it guarantees consistent page sizes"),2,"Cursor pagination avoids the shifting window problem when data changes between pages."),
        quiz("api-7","What is the difference between PUT and PATCH?","medium",("api",),("PUT is exclusively for resource creation; PATCH is for updates only","PATCH is faster because it compresses the request body automatically","PUT replaces the entire resource; PATCH applies a partial update","There is no functional difference; PATCH is just the newer HTTP standard"),2,"PUT requires sending the full resource representation; PATCH sends only changed fields."),
        quiz("api-8","What HTTP status code indicates rate limiting?","medium",("api",),("500 Internal Server Error with a retry hint in the response body","429 Too Many Requests","503 Service Unavailable with a Retry-After header","403 Forbidden due to exceeded API key quota"),1,"429 tells the client to slow down. Usually includes a Retry-After header."),
        quiz("api-9","How should you version your API?","medium",("api",),("URL path (/v1/), query params, or Accept headers","Deploy to different ports for each major version concurrently","Change the domain name for each version (v1.api.com, v2.api.com)","Never version APIs; use feature flags to control behavior per client"),0,"URL path versioning is most common. Header versioning is cleaner but less discoverable."),
        quiz("api-10","What is the purpose of HATEOAS?","hard",("api",),("A standardized error handling format for RESTful API responses","A high-performance caching mechanism for hypermedia API responses","Including links in responses so clients discover available actions dynamically","A rate limiting strategy based on client reputation scoring"),2,"HATEOAS makes APIs self-documenting by embedding navigation links."),
        quiz("api-11","When would you use webhooks?","medium",("api",),("Server needs to notify external clients about events asynchronously","For synchronous authentication flows requiring immediate token validation","For serving large file downloads with resumable transfer support","For database query federation across multiple microservice data stores"),0,"Webhooks push event notifications to registered URLs — used by Stripe, GitHub, Slack."),
        quiz("api-12","What is the difference between sync and async API calls?","medium",("api",),("Sync processes requests in parallel; async processes them sequentially","Sync blocks until response; async returns 202 with a job ID for later polling","They use different HTTP methods (sync=GET, async=POST) by convention","Async API calls don't produce any response; they are fire-and-forget only"),1,"Async APIs return 202 Accepted with a job/task ID. Client polls or gets webhook callback."),
        quiz("api-13","What is an API gateway?","medium",("api",),("A message queue that buffers requests between client and services","A database proxy that handles connection pooling and query routing","A CDN edge function that caches and serves API responses globally","A single entry point handling routing, auth, rate limiting for microservices"),3,"API gateways centralize cross-cutting concerns and simplify client-to-microservice communication."),
        quiz("api-14","What is back-pressure in API design?","hard",("api",),("A mechanism where a service signals upstream it's overwhelmed and should slow down","A compression algorithm that reduces response payload size under high load","A load balancing strategy that favors servers with lower response times","A caching approach where stale data is served while fresh data is computed"),0,"Back-pressure prevents cascade failures by propagating overload signals upstream."),
        quiz("api-15","What is content negotiation?","hard",("api",),("Negotiating API pricing tiers based on client usage volume","Rate limiting based on content type and payload size of each request","API versioning via URL path segments to manage breaking changes","Using Accept/Content-Type headers to agree on response format (JSON, XML, Protobuf)"),3,"Content negotiation lets clients and servers agree on data format via HTTP headers."),
        quiz("api-16","Why shouldn't GET requests modify data?","medium",("api",),("GET requests can't include a JSON body in the request payload","GET requests have a strict 2KB URL length limit across all browsers","GET has higher latency than POST due to additional proxy processing","GET can be cached, bookmarked, retried by browsers/proxies, causing unintended mutations"),3,"GET is defined as safe and idempotent — caches, crawlers, prefetchers may replay them."),
        quiz("api-17","What is the difference between authentication and authorization?","easy",("api",),("Authentication is only required for API calls; authorization is for UI access","Authentication verifies identity; authorization determines what the identity can access","They are the same concept with different names in different frameworks","Authorization must be performed before authentication in the request pipeline"),1,"AuthN (who are you?) comes before AuthZ (what are you allowed to do?)."),
        quiz("api-18","What is API rate limiting?","medium",("api",),("Restricts requests a client can make in a time window to prevent abuse","Encrypts API traffic using TLS certificates rotated on a fixed schedule","Replaces authentication by limiting access based on IP address reputation","Speeds up API responses by pre-computing results for frequent query patterns"),0,"Rate limiting protects services from abuse and ensures fair usage."),
        quiz("api-19","What is the difference between REST and RPC style APIs?","medium",("api",),("REST is resource-oriented (nouns); RPC is action-oriented (verbs)","RPC doesn't use HTTP and requires custom binary transport protocols","They are identical patterns; REST is just the modern name for RPC","REST is faster because it avoids the overhead of method serialization"),0,"REST: GET /users/123. RPC: getUser(123). REST models resources; RPC models operations."),
        quiz("api-20","What is a 201 status code?","easy",("api",),("A redirect response instructing the client to follow a new URL","A generic success response identical in meaning to 200 OK","An empty response indicating the server processed but has no content","Created — successful resource creation, typically via POST"),3,"201 Created is the standard response for successful POST requests that create a resource."),
    ))

def data_modeling_lesson() -> Lesson:
    return Lesson(id="hld-data-modeling", number=102, title="Data Modeling",
        focus=("SQL vs NoSQL","normalization","denormalization","replication","OLTP/OLAP"),
        overview="Choosing the right data model and database is the backbone of every system design.",
        patterns=(), badge="HLD Core", tasks=(
        quiz("dm-1","When would you choose NoSQL over relational?","medium",("data-modeling",),("Schema varies significantly and you need horizontal scalability","When you require strong multi-table ACID transactions across joins","When your data is highly relational with complex foreign key constraints","When you need strict schema enforcement and referential integrity"),0,"Document stores excel at flexible schemas and horizontal scaling, but sacrifice JOINs."),
        quiz("dm-2","What is database normalization?","easy",("data-modeling",),("Encrypting sensitive columns using application-level field encryption","Increasing data size by adding redundant copies for read performance","Organizing data to reduce redundancy by splitting into related tables","Creating indexes on all frequently queried columns for faster lookups"),2,"Normalization (1NF→2NF→3NF) eliminates data redundancy."),
        quiz("dm-3","When is denormalization the right choice?","medium",("data-modeling",),("When the dataset is small enough to fit entirely in application memory","Read performance matters more than write consistency, and you tolerate duplication","When exclusively using NoSQL databases that don't support any joins","Whenever you move from development to production deployment environments"),1,"Denormalization precomputes JOINs, trading storage for read speed."),
        quiz("dm-4","What is the difference between horizontal and vertical partitioning?","medium",("data-modeling",),("They are the same technique with different names in SQL vs NoSQL","Vertical partitioning adds read replicas; horizontal adds write capacity","Horizontal splits rows across shards; vertical splits columns across tables","Horizontal partitioning only works with SQL; vertical only with NoSQL"),2,"Horizontal partitioning (sharding) distributes rows; vertical separates columns."),
        quiz("dm-5","What is database replication?","easy",("data-modeling",),("Copying data across nodes for fault tolerance and read scalability","Moving data from one database engine to another during migration","Encrypting data at rest using transparent data encryption (TDE)","Scheduling daily full backups to a separate storage volume"),0,"Replication ensures availability if one node fails and distributes reads."),
        quiz("dm-6","What is the difference between leader-follower and multi-leader replication?","hard",("data-modeling",),("Leader-follower doesn't actually replicate data; it only logs changes","Leader-follower has one write node; multi-leader allows writes to multiple nodes","Multi-leader is slower because every write needs consensus from all nodes","There is no functional difference; multi-leader is leader-follower with load balancing"),1,"Multi-leader improves write availability but introduces write conflicts."),
        quiz("dm-7","What is eventual consistency?","medium",("data-modeling",),("A database error state where replicas permanently diverge from each other","Data is never consistent and reads always return stale or incorrect values","All replicas converge to same state given enough time without new writes","Reads always return the latest write regardless of which replica is queried"),2,"Eventual consistency trades immediate consistency for availability (AP in CAP)."),
        quiz("dm-8","What is a write-ahead log (WAL)?","hard",("data-modeling",),("An index type that sorts entries by insertion order for faster sequential reads","Changes recorded sequentially before being applied, ensuring durability and crash recovery","A backup schedule that incrementally captures changes since the last snapshot","A query optimizer hint that forces the planner to use a specific execution strategy"),1,"WAL ensures durability: if DB crashes after logging but before applying, it replays on restart."),
        quiz("dm-9","What is the difference between OLTP and OLAP?","medium",("data-modeling",),("They are the same architecture with different marketing names from vendors","OLTP is designed for data warehousing; OLAP handles transactional workloads","OLAP is optimized for fast point writes; OLTP excels at large-scale aggregations","OLTP handles transactional workloads (many small writes); OLAP handles analytics (large aggregations)"),3,"OLTP: PostgreSQL. OLAP: BigQuery, Redshift, ClickHouse."),
        quiz("dm-10","What is the difference between strong consistency and linearizability?","hard",("data-modeling",),("They are identical guarantees expressed using different terminology","Strong ensures reads return latest write; linearizability adds real-time ordering guarantees","Strong consistency is exclusive to SQL databases; linearizability is NoSQL-only","Linearizability is a weaker guarantee that tolerates stale reads within a time window"),1,"Linearizability is the strongest: operations appear atomic at some point between invocation and response."),
        quiz("dm-11","What is a materialized view?","medium",("data-modeling",),("A regular database view that executes its query on every access","A temporary cache layer managed by the application outside the database","A precomputed query result stored as a table, periodically refreshed","A specialized index type optimized for full-text search operations"),2,"Materialized views precompute expensive JOINs/aggregations. Great for dashboards."),
        quiz("dm-12","What is a tombstone in distributed databases?","hard",("data-modeling",),("An index entry marking a row as recently updated for cache invalidation","A backup mechanism that preserves deleted data for point-in-time recovery","A marker for deleted records, propagating deletions across replicas before compaction","A crashed server that still holds its partition lease, blocking reassignment"),2,"Tombstones prevent deleted data from being resurrected by replicas."),
        quiz("dm-13","What is optimistic vs pessimistic locking?","hard",("data-modeling",),("Optimistic always outperforms pessimistic regardless of contention level","Pessimistic doesn't actually use locks; it relies on serializable isolation instead","They are identical strategies; the choice is purely a naming convention preference","Optimistic assumes no conflict and checks at commit; pessimistic locks upfront"),3,"Optimistic (version numbers) for low contention. Pessimistic (SELECT FOR UPDATE) prevents conflicts."),
        quiz("dm-14","What is a wide-column store?","hard",("data-modeling",),("A relational table designed with hundreds of nullable columns for flexibility","A NoSQL store where rows can have different columns, organized by partition+clustering keys","A document database that stores each field as a separate JSON document","A graph database that represents edges as columns in an adjacency matrix"),1,"Cassandra/HBase: data organized by partition key, columns can vary per row. Ideal for write-heavy workloads."),
        quiz("dm-15","What is the difference between a document store and a key-value store?","medium",("data-modeling",),("Document stores understand document structure (query by fields); KV stores treat values as opaque blobs","They are identical; document stores are just key-value stores with JSON serialization","Key-value stores are newer and support richer query capabilities than document stores","Document stores can't support queries on nested data; they only allow full-document retrieval"),0,"MongoDB (document) lets you query by nested fields. Redis/DynamoDB (KV) primarily support key lookup."),
        quiz("dm-16","What is a graph database best suited for?","medium",("data-modeling",),("Simple key-value lookups with extremely high read throughput requirements","Highly connected data with complex relationship traversals (social networks, recommendations)","Flat tabular data with strong schema enforcement and ACID transactions","Time-series data with high-frequency append-only writes and range queries"),1,"Graph DBs (Neo4j) excel at traversing relationships — friend-of-friend queries in O(k) per hop."),
        quiz("dm-17","What is the difference between row-oriented and column-oriented storage?","hard",("data-modeling",),("Row-oriented is always faster for both OLTP and OLAP workloads","Row stores data row-by-row (good for OLTP); column stores column-by-column (good for analytics)","Column-oriented storage cannot perform aggregation queries like SUM or AVG","They store data identically but differ in how indexes are structured internally"),1,"Column stores (Parquet, ClickHouse) compress better and scan only needed columns for analytics."),
        quiz("dm-18","What is data partitioning by range vs hash?","medium",("data-modeling",),("Range partitioning doesn't work with string keys, only with integers","Hash partitioning is always superior because it guarantees even distribution","They are fundamentally the same approach with different implementation details","Range assigns key ranges to partitions (supports scans); hash distributes evenly (no range queries)"),3,"Range supports range queries but risks hotspots. Hash distributes evenly but loses range capability."),
        quiz("dm-19","What is multi-tenancy in database design?","medium",("data-modeling",),("Running multiple separate database instances on different physical servers","Multiple customers share the same DB/tables, isolated by tenant_id column or schema","Assigning one customer per dedicated server for maximum resource isolation","A replication strategy where each tenant's data is synced to a different region"),1,"Multi-tenancy options: shared DB + tenant column, separate schemas, or separate databases."),
        quiz("dm-20","What is a time-series database optimized for?","medium",("data-modeling",),("Full-text search with relevance scoring and fuzzy matching capabilities","Storing user profiles with complex nested relationships and access patterns","Append-heavy workloads with timestamp-ordered data like metrics, IoT, financial data","Graph traversals for recommendation engines and social network analysis"),2,"Time-series DBs (InfluxDB, TimescaleDB) optimize for high write throughput and time-range queries."),
    ))
